#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long cntOne = 0, cntEven = 0;
        for (int i = 0; i < N; ++i) {
            long long a; scanf("%lld", &a);
            if (a == 1) cntOne++;
            else if ((a & 1LL) == 0) cntEven++;
        }
        int x = (cntOne & 1LL) ^ ((cntEven & 1LL) << 1);
        if (x) printf("CHEF\n");
        else    printf("CHEFINA\n");
    }
    return 0;
}

